// Example: minimal CI check for dependency vulnerabilities
const { execSync } = require('child_process');

const ALLOWED_SEVERITIES = ['low', 'medium'];
const CRITICAL_SEVERITIES = ['high', 'critical'];

function checkVulnerabilities() {
  try {
    const output = execSync('npm audit --json', { encoding: 'utf8' });
    const audit = JSON.parse(output);

    const criticalVulns = audit.vulnerabilities.filter(v => 
      CRITICAL_SEVERITIES.includes(v.severity)
    );

    if (criticalVulns.length > 0) {
      console.error('Blocking build: critical vulnerabilities found');
      process.exit(1);
    }
  } catch (e) {
    console.error('Audit failed:', e.message);
    process.exit(1);
  }
}

checkVulnerabilities();
```

