const crypto = require('crypto');

function verifySignature(payload, sig, key, ts, nonce, seenNonces, windowSeconds = 300) {
  const now = Math.floor(Date.now() / 1000);
  const timestamp = parseInt(ts, 10);

  if (Math.abs(now - timestamp) > windowSeconds) {
    throw new Error('Timestamp outside valid window');
  }

  if (seenNonces.has(nonce)) {
    throw new Error('Nonce already seen - replay detected');
  }
  seenNonces.add(nonce);

  const expectedSig = crypto
    .createHmac('sha256', key)
    .update(`${ts}.${nonce}.${payload}`)
    .digest('hex');

  if (!crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expectedSig))) {
    throw new Error('Invalid signature');
  }

  return true;
}

function idempotentHandler(eventId, handler) {
  const lock = redis.lock(`event:${eventId}`);
  if (!lock.acquire()) return { status: 'already_processing' };

  try {
    const result = cache.get(`processed:${eventId}`);
    if (result) return { status: 'duplicate', result };

    const output = handler();
    cache.set(`processed:${eventId}`, output, { ttl: 86400 });
    return { status: 'processed', result: output };
  } finally {
    lock.release();
  }
}
```

